# Day 36: Debugging: Using print, breakpoints, and VS Code Debugger
# Debugging Techniques

# 1. Read the traceback
def buggy_divide(a, b):
    try:
        return a / b
    except ZeroDivisionError:
        print(f"ERROR: Cannot divide {a} by {b}")
        return None

result = buggy_divide(10, 0)

# 2. Print debugging
def find_avg(nums):
    print(f"DEBUG: nums = {nums}")        # debug print
    print(f"DEBUG: len = {len(nums)}")     # debug print
    if not nums:
        return 0
    total = sum(nums)
    print(f"DEBUG: total = {total}")       # debug print
    return total / len(nums)

find_avg([10, 20, 30])

# 3. Assert statements
def set_age(age):
    assert 0 <= age <= 150, f"Invalid age: {age}"
    return age

try:
    set_age(200)
except AssertionError as e:
    print(f"Assertion failed: {e}")
